        tested = 0
        dec = 0  # how much cumulative decrement applies to current index

        for i, b in enumerate(batteryPercentages):
            current = b - dec
            if current > 0:
                tested += 1
                dec += 1  # testing device i decrements all later devices by 1
        return tested
